CREATE TABLE content_field_values (revision_id VARCHAR(36) NOT NULL, entry_id VARCHAR(36) NOT NULL, model_id VARCHAR(36) NOT NULL, field_id VARCHAR(36) NOT NULL, value_type ENUM('string', 'integer', 'decimal', 'boolean', 'date', 'datetime') NOT NULL, string_value LONGTEXT CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_as_cs NULL, integer_value BIGINT NULL, decimal_value DECIMAL(65,30) NULL, boolean_value BOOLEAN NULL, date_value DATE NULL, datetime_value DATETIME(6) NULL, PRIMARY KEY (revision_id, field_id), KEY idx_content_field_values_string (model_id, field_id, string_value(191), revision_id, entry_id), KEY idx_content_field_values_integer (model_id, field_id, integer_value, revision_id, entry_id), KEY idx_content_field_values_decimal (model_id, field_id, decimal_value, revision_id, entry_id), KEY idx_content_field_values_boolean (model_id, field_id, boolean_value, revision_id, entry_id), KEY idx_content_field_values_date (model_id, field_id, date_value, revision_id, entry_id), KEY idx_content_field_values_datetime (model_id, field_id, datetime_value, revision_id, entry_id), CONSTRAINT fk_content_field_values_revision FOREIGN KEY (revision_id, entry_id, model_id) REFERENCES content_revisions (id, entry_id, model_id), CONSTRAINT fk_content_field_values_field FOREIGN KEY (field_id, model_id) REFERENCES content_fields (id, model_id), CONSTRAINT chk_content_field_values_typed CHECK ((value_type = 'string') + (value_type = 'integer') + (value_type = 'decimal') + (value_type = 'boolean') + (value_type = 'date') + (value_type = 'datetime') = 1 AND (string_value IS NOT NULL) + (integer_value IS NOT NULL) + (decimal_value IS NOT NULL) + (boolean_value IS NOT NULL) + (date_value IS NOT NULL) + (datetime_value IS NOT NULL) = 1 AND (value_type = 'string') = (string_value IS NOT NULL) AND (value_type = 'integer') = (integer_value IS NOT NULL) AND (value_type = 'decimal') = (decimal_value IS NOT NULL) AND (value_type = 'boolean') = (boolean_value IS NOT NULL) AND (value_type = 'date') = (date_value IS NOT NULL) AND (value_type = 'datetime') = (datetime_value IS NOT NULL))) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_as_cs;
